F = 2*Q - D;
draw(P--D--EE--F--D);
draw(EE--Q);
label("$D$",D,E);
label("$P$",P,NW);
label("$Q$",Q,SE);
label("$E$",EE,N);
label("$F$",F,SW);
draw(rightanglemark(Q,G,D,3.5));
